function mergeSort(arr) {
    if (arr.length < 2) return arr;
    const mid = Math.floor(arr.length / 2);
    const left = mergeSort(arr.slice(0, mid));
    const right = mergeSort(arr.slice(mid));
    const result = [];
    let i = 0, j = 0;
    while (i < left.length && j < right.length) {
        if (left[i] <= right[j]) result.push(left[i++]);
        else result.push(right[j++]);
    }
    while (i < left.length) result.push(left[i++]);
    while (j < right.length) result.push(right[j++]);
    return result;
}
const n = parseInt(process.argv[2]);
let arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) {
    seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648;
    arr[i] = (seed >> 16) & 0x7fff;
}
arr = mergeSort(arr);
let checksum = 0;
for (const v of arr) checksum = (checksum + v) % 1000000007;
console.log(`${arr[0]} ${arr[n - 1]} ${checksum}`);

function partition(arr, lo, hi) {
    const pivot = arr[hi]; let i = lo;
    for (let j = lo; j < hi; j++)
        if (arr[j] <= pivot) { [arr[i], arr[j]] = [arr[j], arr[i]]; i++; }
    [arr[i], arr[hi]] = [arr[hi], arr[i]];
    return i;
}
function qs(arr, lo, hi) {
    if (lo < hi) { const p = partition(arr, lo, hi); qs(arr, lo, p-1); qs(arr, p+1, hi); }
}
const n = parseInt(process.argv[2]);
const arr = new Array(n);
let seed = 42;
for (let i = 0; i < n; i++) { seed = ((Math.imul(seed, 1103515245) + 12345) >>> 0) % 2147483648; arr[i] = (seed>>16)&0x7fff; }
qs(arr, 0, n-1);
let checksum = 0;
for (const v of arr) checksum = (checksum + v) % 1000000007;
console.log(`${arr[0]} ${arr[n-1]} ${checksum}`);

function makeCheck(d) { return d === 0 ? 1 : 1 + makeCheck(d-1) + makeCheck(d-1); }
const n = parseInt(process.argv[2]), mn = 4;
let mx = Math.max(mn + 2, n);
console.log(`stretch tree of depth ${mx+1}\t check: ${makeCheck(mx+1)}`);
const ll = makeCheck(mx);
for (let d = mn; d <= mx; d += 2) {
    const it = 1 << (mx - d + mn); let tc = 0;
    for (let i = 0; i < it; i++) tc += makeCheck(d);
    console.log(`${it}\t trees of depth ${d}\t check: ${tc}`);
}
console.log(`long lived tree of depth ${mx}\t check: ${ll}`);

